   138→void RpcClientImpl::ResetOptions(const RpcClientOptions& options)
   139→{
   140→    int64 old_slice_quota_in = _slice_quota_in;
   141→    int64 old_slice_quota_out = _slice_quota_out;
   142→    int64 old_max_pending_buffer_size = _max_pending_buffer_size;
   143→    int64 old_keep_alive_ticks = _keep_alive_ticks;
   144→
   145→    _options.max_throughput_in = options.max_throughput_in;
   146→    _options.max_throughput_out = options.max_throughput_out;
   147→    _options.max_pending_buffer_size = options.max_pending_buffer_size;
   148→    _options.keep_alive_time = options.keep_alive_time;
   149→
   150→    _slice_quota_in = _options.max_throughput_in == -1 ?
   151→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
   152→    _slice_quota_out = _options.max_throughput_out == -1 ?
   153→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
   154→    _max_pending_buffer_size =
   155→        std::max(0L, options.max_pending_buffer_size * 1024L * 1024L);
   156→    _keep_alive_ticks = _options.keep_alive_time == -1 ?
   157→        -1 : std::max(1, _options.keep_alive_time) * _ticks_per_second;
   158→
   159→    if (_max_pending_buffer_size != old_max_pending_buffer_size)
   160→    {
   161→        ScopedLocker<FastLock> _(_stream_map_lock);
   162→        for (StreamMap::iterator it = _stream_map.begin(); it != _stream_map.end(); )
   163→        {
   164→            it->second->set_max_pending_buffer_size(_max_pending_buffer_size);
   165→        }
   166→    }
   167→
   168→#if defined( LOG )
   169→    LOG(INFO) << "ResetOptions(): quota_in="
   170→              << (_slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L))
   171→              << "MB/s(old "
   172→              << (old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L))
   173→              << "MB/s), quota_out="
   174→              << (_slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L))
   175→              << "MB/s(old "
   176→              << (old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L))
   177→              << "MB/s), max_pending_buffer_size="
   178→              << (_max_pending_buffer_size / (1024L * 1024L))
   179→              << "MB(old "
   180→              << (old_max_pending_buffer_size / (1024L * 1024L))
   181→              << "MB), keep_alive_time="
   182→              << (_keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second)
   183→              << "seconds(old "
   184→              << (old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second)
   185→              << "seconds)";
   186→#else
   187→    SLOG(INFO, "ResetOptions(): quota_in=%lldMB/s(old %lldMB/s)"
   188→            ", quota_out=%lldMB/s(old %lldMB/s)"
   189→            ", max_pending_buffer_size=%lldMB(old %lldMB)",
   190→            ", keep_alive_time=%lldseconds(old %lldseconds)",
   191→            _slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L),
   192→            old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L),
   193→            _slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L),
   194→            old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L),
   195→            _max_pending_buffer_size / (1024L * 1024L),
   196→            old_max_pending_buffer_size / (1024L * 1024L),
   197→            _keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second,
   198→            old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second);
   199→#endif
   200→}
